+  bool canEvaluateShifted(Value *V, unsigned NumBits, bool IsLeftShift,
+                          ShiftSemantics Semantics, Instruction *CxtI);
+  Value *getShiftedValue(Value *V, unsigned NumBits, bool IsLeftShift,
+                         ShiftSemantics Semantics);
+
