-static bool canEvaluateShifted(Value *V, unsigned NumBits, bool IsLeftShift,
-                               InstCombinerImpl &IC, Instruction *CxtI) {
-  // We can always evaluate immediate constants.
-  if (match(V, m_ImmConstant()))
