538 /// Return true if we can simplify two logical (either left or right) shifts
539 /// that have constant shift amounts: OuterShift (InnerShift X, C1), C2.
540 static bool canEvaluateShiftedShift(unsigned OuterShAmt, bool IsOuterShl,
541                                     ShiftSemantics Semantics,
542                                     Instruction *InnerShift,
543                                     InstCombinerImpl &IC, Instruction *CxtI) {
544   assert(InnerShift->isLogicalShift() && "Unexpected instruction type");
545 
546   // We need constant scalar or constant splat shifts.
547   const APInt *InnerShiftConst;
548   if (!match(InnerShift->getOperand(1), m_APInt(InnerShiftConst)))
549     return false;
550 
551   // Two logical shifts in the same direction:
552   // shl (shl X, C1), C2 -->  shl X, C1 + C2
553   // lshr (lshr X, C1), C2 --> lshr X, C1 + C2
554   bool IsInnerShl = InnerShift->getOpcode() == Instruction::Shl;
555 
556   if (!IsOuterShl && Semantics == ShiftSemantics::Signed)
557     return IsInnerShl && cast<BinaryOperator>(InnerShift)->hasNoSignedWrap() &&
558            *InnerShiftConst == OuterShAmt;
559   if (IsInnerShl == IsOuterShl)
560     return Semantics == ShiftSemantics::Lossy;
561 
562   // Equal shift amounts in opposite directions become bitwise 'and':
563   // lshr (shl X, C), C --> and X, C'
564   // shl (lshr X, C), C --> and X, C'
565   if (*InnerShiftConst == OuterShAmt)
566     return true;
567 
568   // If the 2nd shift is bigger than the 1st, we can fold:
569   // lshr (shl X, C1), C2 -->  and (shl X, C1 - C2), C3
570   // shl (lshr X, C1), C2 --> and (lshr X, C1 - C2), C3
571   // but it isn't profitable unless we know the and'd out bits are already zero.
572   // Also, check that the inner shift is valid (less than the type width) or
573   // we'll crash trying to produce the bit mask for the 'and'.
574   unsigned TypeWidth = InnerShift->getType()->getScalarSizeInBits();
575   if (InnerShiftConst->ugt(OuterShAmt) && InnerShiftConst->ult(TypeWidth)) {
576     unsigned InnerShAmt = InnerShiftConst->getZExtValue();
577     unsigned MaskShift =
578         IsInnerShl ? TypeWidth - InnerShAmt : InnerShAmt - OuterShAmt;
579     APInt Mask = APInt::getLowBitsSet(TypeWidth, OuterShAmt) << MaskShift;
580     if (IC.MaskedValueIsZero(InnerShift->getOperand(0), Mask, CxtI))
581       return true;
582   }
583 
584   return false;
585 }
