587 /// See if we can compute the specified value, but shifted logically to the left
588 /// or right by some number of bits. This should return true if the
589 /// transformation is valid. If the Semantics is not lossy,
590 /// we must get the same value when we shift this value and then shift back.
591 /// This is used to eliminate extraneous shifting from things like:
592 ///      %C = shl i128 %A, 64
593 ///      %D = shl i128 %B, 96
594 ///      %E = or i128 %C, %D
595 ///      %F = lshr i128 %E, 64
596 /// where the client will ask if E can be computed shifted right by 64-bits. If
597 /// this succeeds, getShiftedValue() will be called to produce the value.
598 bool InstCombinerImpl::canEvaluateShifted(Value *V, unsigned NumBits,
599                                           bool IsLeftShift,
600                                           ShiftSemantics Semantics,
601                                           Instruction *CxtI) {
602   // We can always evaluate immediate constants shifted left. For right shifts,
603   // the constant must be a multiple of 2^NumBits to avoid losing information.
604   if (match(V, m_ImmConstant())) {
605     if (Semantics == ShiftSemantics::Lossy)
606       return true;
607     const APInt *C;
608     if (match(V, m_APIntAllowPoison(C)) && !IsLeftShift)
609       return C->countr_zero() >= NumBits;
610     return false;
611   }
612 
613   Instruction *I = dyn_cast<Instruction>(V);
614   if (!I) return false;
615 
616   // We can't mutate something that has multiple uses: doing so would
617   // require duplicating the instruction in general, which isn't profitable.
618   if (!I->hasOneUse()) return false;
619 
620   switch (I->getOpcode()) {
621   default: return false;
622   case Instruction::And:
623   case Instruction::Or:
624   case Instruction::Xor:
625     // Bitwise operators can all arbitrarily be arbitrarily evaluated shifted.
626     return canEvaluateShifted(I->getOperand(0), NumBits, IsLeftShift, Semantics,
627                               I) &&
628            canEvaluateShifted(I->getOperand(1), NumBits, IsLeftShift, Semantics,
629                               I);
630 
631   case Instruction::Shl:
632   case Instruction::LShr:
633     return canEvaluateShiftedShift(NumBits, IsLeftShift, Semantics, I, *this,
634                                    CxtI);
635 
636   case Instruction::Select: {
637     SelectInst *SI = cast<SelectInst>(I);
638     Value *TrueVal = SI->getTrueValue();
639     Value *FalseVal = SI->getFalseValue();
640     return canEvaluateShifted(TrueVal, NumBits, IsLeftShift, Semantics, SI) &&
641            canEvaluateShifted(FalseVal, NumBits, IsLeftShift, Semantics, SI);
642   }
643   case Instruction::PHI: {
644     // We can change a phi if we can change all operands.  Note that we never
645     // get into trouble with cyclic PHIs here because we only consider
646     // instructions with a single use.
647     PHINode *PN = cast<PHINode>(I);
648     for (Value *IncValue : PN->incoming_values())
649       if (!canEvaluateShifted(IncValue, NumBits, IsLeftShift, Semantics, PN))
650         return false;
651     return true;
652   }
653   case Instruction::Mul: {
654     const APInt *MulConst;
655     // We can fold (shr (mul X, -(1 << C)), C) -> (and (neg X), C`)
656     return !IsLeftShift && Semantics == ShiftSemantics::Unsigned &&
657            match(I->getOperand(1), m_APInt(MulConst)) &&
658            MulConst->isNegatedPowerOf2() && MulConst->countr_zero() == NumBits;
659   }
660   case Instruction::Add: {
661     auto *BinOp = cast<BinaryOperator>(I);
662     // Left shift case
663     if (IsLeftShift) {
664       if (Semantics == ShiftSemantics::Lossy)
665         return canEvaluateShifted(I->getOperand(0), NumBits, IsLeftShift,
666                                   Semantics, I) &&
667                canEvaluateShifted(I->getOperand(1), NumBits, IsLeftShift,
668                                   Semantics, I);
669 
670       return false;
671     }
672 
673     if (Semantics == ShiftSemantics::Lossy)
674       return false;
675     bool WrapRequired =
676         (Semantics == ShiftSemantics::Signed && BinOp->hasNoSignedWrap()) ||
677         (Semantics == ShiftSemantics::Unsigned && BinOp->hasNoUnsignedWrap());
678     return WrapRequired &&
679            canEvaluateShifted(I->getOperand(0), NumBits, IsLeftShift, Semantics,
680                               I) &&
681            canEvaluateShifted(I->getOperand(1), NumBits, IsLeftShift, Semantics,
682                               I);
683   }
684   }
685 }
